<?php namespace App\Repositories\Admission;use App\Repositories\BaseRepository;use App\Models\Admission\EntranceExamResult;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class EntranceExamResultRepository extends BaseRepository{    public function __construct(EntranceExamResult $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByExam(int $examId): Collection    {        return $this->findByField('entrance_exam_id', $examId);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function getPassedResults(): Collection    {        return $this->query()->where('is_passed', true)->get();    }    public function getFailedResults(): Collection    {        return $this->query()->where('is_passed', false)->get();    }    public function getRankings(int $examId): Collection    {        return $this->query()->where('entrance_exam_id', $examId)->orderBy('total_marks', 'desc')->get();    }    public function findByScoreRange(int $examId, float $minScore, float $maxScore): Collection    {        return $this->query()->where('entrance_exam_id', $examId)->whereBetween('total_marks', [$minScore, $maxScore])->get();    }}